defmodule XmlController do
  use Plug.ShowException

  plug :accepts, ["application/xml"]
  plug SweetXmlParser.Plug

  def index(conn, %{"body" => body}) when is_binary(body)  do
    xml = XML.parse(body)

    case xml |> xpath("xml/root/name") do
      {:ok, nodes} ->
        IO.inspect nodes
        {:ok, "Hello world"}

